INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (1, '2026-01-01', 'La fe madura cuando Cristo deja de ser una idea y se vuelve el pan del día; antes de hablar del mundo, permite que Dios juzgue su propio corazón.', 'Charles Spurgeon');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (2, '2026-01-02', 'La cruz se entiende mejor cuando el evangelio consuela sin adormecer la conciencia; porque Dios no desperdicia ni lágrimas ni obediencias escondidas.', 'Martín Lutero');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (3, '2026-01-03', 'La obediencia florece cuando la cruz transforma la pérdida en altar de entrega; sin ese centro, aun lo religioso se vuelve ruido.', 'Juan Calvino');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (4, '2026-01-04', 'La humildad gobierna cuando la vida interior gobierna las obras exteriores; esa es la raíz de una piedad que no se marchita.', 'Watchman Nee');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (5, '2026-01-05', 'La oración se vuelve profunda cuando la gracia no excusa el pecado, sino que lo vence desde adentro; esa certeza sostiene la obra cuando faltan aplausos.', 'Witness Lee');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (6, '2026-01-06', 'La adoración se purifica cuando la esperanza mira más lejos que la tormenta presente; y la obediencia deja de ser carga para volverse respuesta.', 'Billy Graham');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (7, '2026-01-07', 'El temor de Dios sana cuando la verdad se defiende con firmeza y se ofrece con ternura; y la vida entera empieza a decir: Cristo basta.', 'C.S. Lewis');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (8, '2026-01-08', 'La iglesia se fortalece cuando la misión se alimenta de adoración antes que de estrategia; esa certeza sostiene la obra cuando faltan aplausos.', 'Agustín de Hipona');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (9, '2026-01-09', 'La esperanza permanece cuando la obediencia se convierte en gratitud visible; y la obediencia deja de ser carga para volverse respuesta.', 'A.W. Tozer');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (10, '2026-01-10', 'El servicio pesa menos cuando la cruz transforma la pérdida en altar de entrega; y la vida entera empieza a decir: Cristo basta.', 'Francis Schaeffer');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (11, '2026-01-11', 'La fe madura cuando la fe no niega la noche, pero recuerda al Señor de la mañana; y el alma descubre que perderse en Cristo es ganarse de verdad.', 'Martyn Lloyd-Jones');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (12, '2026-01-12', 'La cruz se entiende mejor cuando la providencia se recibe como disciplina de un Padre sabio; porque el Señor no solo salva, también forma.', 'John Piper');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (13, '2026-01-13', 'La obediencia florece cuando la esperanza mira más lejos que la tormenta presente; entonces la teología termina arrodillada en adoración.', 'John MacArthur');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (14, '2026-01-14', 'La humildad gobierna cuando la eternidad corrige las urgencias del presente; porque la verdad de Dios nunca necesita disfrazarse.', 'R.C. Sproul');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (15, '2026-01-15', 'La oración se vuelve profunda cuando la santidad abandona la máscara y busca limpieza real; porque el Señor no solo salva, también forma.', 'Dietrich Bonhoeffer');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (16, '2026-01-16', 'La adoración se purifica cuando la obediencia se convierte en gratitud visible; entonces la teología termina arrodillada en adoración.', 'Jonathan Edwards');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (17, '2026-01-17', 'El temor de Dios sana cuando la Escritura ilumina tanto el camino como el caminante; porque la verdad de Dios nunca necesita disfrazarse.', 'George Whitefield');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (18, '2026-01-18', 'La iglesia se fortalece cuando la gracia convierte la culpa en confesión y la confesión en libertad; y aun las tareas pequeñas reciben peso eterno.', 'John Wesley');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (19, '2026-01-19', 'La esperanza permanece cuando la providencia se recibe como disciplina de un Padre sabio; porque la gracia no solo perdona: también gobierna.', 'John Owen');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (20, '2026-01-20', 'El servicio pesa menos cuando el servicio se hace para Dios y no para ser visto; esa es la seriedad gozosa del discipulado.', 'J.C. Ryle');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (21, '2026-01-21', 'La fe madura cuando la misericordia recibida se vuelve misericordia practicada; entonces la vida común se vuelve terreno santo.', 'Thomas Watson');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (22, '2026-01-22', 'La cruz se entiende mejor cuando la santidad abandona la máscara y busca limpieza real; porque la gracia no solo perdona: también gobierna.', 'George Müller');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (23, '2026-01-23', 'La obediencia florece cuando el amor de Dios ordena todos los amores inferiores; esa es la seriedad gozosa del discipulado.', 'Andrew Murray');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (24, '2026-01-24', 'La humildad gobierna cuando la gracia enseña a depender y no a presumir; entonces la vida común se vuelve terreno santo.', 'Oswald Chambers');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (25, '2026-01-25', 'La oración se vuelve profunda cuando la gracia convierte la culpa en confesión y la confesión en libertad; y la esperanza se vuelve más fuerte que el cansancio.', 'Corrie ten Boom');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (26, '2026-01-26', 'La adoración se purifica cuando la cruz mata el orgullo que la religión suele esconder; donde Cristo reina, el temor pierde su trono.', 'Elisabeth Elliot');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (27, '2026-01-27', 'El temor de Dios sana cuando la mente se arrodilla ante la revelación antes de razonar; allí comienza una libertad que ninguna circunstancia puede quitar.', 'Tim Keller');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (28, '2026-01-28', 'La iglesia se fortalece cuando la misericordia recibida se vuelve misericordia practicada; allí el evangelio deja de ser tema y se vuelve sustento.', 'Herman Bavinck');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (29, '2026-01-29', 'La esperanza permanece cuando el gozo se arraiga en Dios y no en circunstancias favorables; donde Cristo reina, el temor pierde su trono.', 'Abraham Kuyper');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (30, '2026-01-30', 'El servicio pesa menos cuando la verdad no se negocia para ganar comodidad; allí comienza una libertad que ninguna circunstancia puede quitar.', 'J.I. Packer');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (31, '2026-01-31', 'La fe madura cuando la gracia enseña a depender y no a presumir; allí el evangelio deja de ser tema y se vuelve sustento.', 'John Stott');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (32, '2026-02-01', 'La cruz se entiende mejor cuando el alma aprende a vivir de promesas y no de impresiones; así la fe aprende a caminar sin exigir espectáculo.', 'Richard Baxter');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (33, '2026-02-02', 'La obediencia florece cuando la gloria de Dios pesa más que la aprobación de los hombres; antes de hablar del mundo, permite que Dios juzgue su propio corazón.', 'Charles Spurgeon');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (34, '2026-02-03', 'La humildad gobierna cuando la mente se arrodilla ante la revelación antes de razonar; porque Dios no desperdicia ni lágrimas ni obediencias escondidas.', 'Martín Lutero');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (35, '2026-02-04', 'La oración se vuelve profunda cuando el carácter se forma donde nadie aplaude; sin ese centro, aun lo religioso se vuelve ruido.', 'Juan Calvino');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (36, '2026-02-05', 'La adoración se purifica cuando la humildad deja de compararse y empieza a obedecer; antes de hablar del mundo, permite que Dios juzgue su propio corazón.', 'Watchman Nee');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (37, '2026-02-06', 'El temor de Dios sana cuando la verdad no se negocia para ganar comodidad; porque Dios no desperdicia ni lágrimas ni obediencias escondidas.', 'Witness Lee');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (38, '2026-02-07', 'La iglesia se fortalece cuando el corazón encuentra reposo en la suficiencia de Cristo; sin ese centro, aun lo religioso se vuelve ruido.', 'Billy Graham');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (39, '2026-02-08', 'La esperanza permanece cuando la adoración mira primero quién es Dios y luego qué hace; esa es la raíz de una piedad que no se marchita.', 'C.S. Lewis');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (40, '2026-02-09', 'El servicio pesa menos cuando la gloria de Dios pesa más que la aprobación de los hombres; esa certeza sostiene la obra cuando faltan aplausos.', 'Agustín de Hipona');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (41, '2026-02-10', 'La fe madura cuando la fe acepta la voluntad de Dios sin exigir explicaciones; y la obediencia deja de ser carga para volverse respuesta.', 'A.W. Tozer');
