INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (302, '2026-10-29', 'La cruz se entiende mejor cuando el evangelio consuela sin adormecer la conciencia; porque la gracia no solo perdona: también gobierna.', 'R.C. Sproul');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (303, '2026-10-30', 'La obediencia florece cuando la cruz transforma la pérdida en altar de entrega; esa es la seriedad gozosa del discipulado.', 'Dietrich Bonhoeffer');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (304, '2026-10-31', 'La humildad gobierna cuando la vida interior gobierna las obras exteriores; entonces la vida común se vuelve terreno santo.', 'Jonathan Edwards');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (305, '2026-11-01', 'La oración se vuelve profunda cuando la gracia no excusa el pecado, sino que lo vence desde adentro; y la esperanza se vuelve más fuerte que el cansancio.', 'George Whitefield');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (306, '2026-11-02', 'La adoración se purifica cuando la esperanza mira más lejos que la tormenta presente; donde Cristo reina, el temor pierde su trono.', 'John Wesley');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (307, '2026-11-03', 'El temor de Dios sana cuando la verdad se defiende con firmeza y se ofrece con ternura; allí comienza una libertad que ninguna circunstancia puede quitar.', 'John Owen');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (308, '2026-11-04', 'La iglesia se fortalece cuando la misión se alimenta de adoración antes que de estrategia; allí el evangelio deja de ser tema y se vuelve sustento.', 'J.C. Ryle');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (309, '2026-11-05', 'La esperanza permanece cuando la obediencia se convierte en gratitud visible; donde Cristo reina, el temor pierde su trono.', 'Thomas Watson');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (310, '2026-11-06', 'El servicio pesa menos cuando la cruz transforma la pérdida en altar de entrega; allí comienza una libertad que ninguna circunstancia puede quitar.', 'George Müller');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (311, '2026-11-07', 'La fe madura cuando la fe no niega la noche, pero recuerda al Señor de la mañana; allí el evangelio deja de ser tema y se vuelve sustento.', 'Andrew Murray');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (312, '2026-11-08', 'La cruz se entiende mejor cuando la providencia se recibe como disciplina de un Padre sabio; así la fe aprende a caminar sin exigir espectáculo.', 'Oswald Chambers');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (313, '2026-11-09', 'La obediencia florece cuando la esperanza mira más lejos que la tormenta presente; antes de hablar del mundo, permite que Dios juzgue su propio corazón.', 'Corrie ten Boom');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (314, '2026-11-10', 'La humildad gobierna cuando la eternidad corrige las urgencias del presente; porque Dios no desperdicia ni lágrimas ni obediencias escondidas.', 'Elisabeth Elliot');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (315, '2026-11-11', 'La oración se vuelve profunda cuando la santidad abandona la máscara y busca limpieza real; sin ese centro, aun lo religioso se vuelve ruido.', 'Tim Keller');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (316, '2026-11-12', 'La adoración se purifica cuando la obediencia se convierte en gratitud visible; antes de hablar del mundo, permite que Dios juzgue su propio corazón.', 'Herman Bavinck');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (317, '2026-11-13', 'El temor de Dios sana cuando la Escritura ilumina tanto el camino como el caminante; porque Dios no desperdicia ni lágrimas ni obediencias escondidas.', 'Abraham Kuyper');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (318, '2026-11-14', 'La iglesia se fortalece cuando la gracia convierte la culpa en confesión y la confesión en libertad; sin ese centro, aun lo religioso se vuelve ruido.', 'J.I. Packer');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (319, '2026-11-15', 'La esperanza permanece cuando la providencia se recibe como disciplina de un Padre sabio; esa es la raíz de una piedad que no se marchita.', 'John Stott');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (320, '2026-11-16', 'El servicio pesa menos cuando el servicio se hace para Dios y no para ser visto; esa certeza sostiene la obra cuando faltan aplausos.', 'Richard Baxter');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (321, '2026-11-17', 'La fe madura cuando la misericordia recibida se vuelve misericordia practicada; y la obediencia deja de ser carga para volverse respuesta.', 'Charles Spurgeon');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (322, '2026-11-18', 'La cruz se entiende mejor cuando la santidad abandona la máscara y busca limpieza real; y la vida entera empieza a decir: Cristo basta.', 'Martín Lutero');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (323, '2026-11-19', 'La obediencia florece cuando el amor de Dios ordena todos los amores inferiores; esa certeza sostiene la obra cuando faltan aplausos.', 'Juan Calvino');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (324, '2026-11-20', 'La humildad gobierna cuando la gracia enseña a depender y no a presumir; y la obediencia deja de ser carga para volverse respuesta.', 'Watchman Nee');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (325, '2026-11-21', 'La oración se vuelve profunda cuando la gracia convierte la culpa en confesión y la confesión en libertad; y la vida entera empieza a decir: Cristo basta.', 'Witness Lee');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (326, '2026-11-22', 'La adoración se purifica cuando la cruz mata el orgullo que la religión suele esconder; y el alma descubre que perderse en Cristo es ganarse de verdad.', 'Billy Graham');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (327, '2026-11-23', 'El temor de Dios sana cuando la mente se arrodilla ante la revelación antes de razonar; porque el Señor no solo salva, también forma.', 'C.S. Lewis');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (328, '2026-11-24', 'La iglesia se fortalece cuando la misericordia recibida se vuelve misericordia practicada; entonces la teología termina arrodillada en adoración.', 'Agustín de Hipona');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (329, '2026-11-25', 'La esperanza permanece cuando el gozo se arraiga en Dios y no en circunstancias favorables; porque la verdad de Dios nunca necesita disfrazarse.', 'A.W. Tozer');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (330, '2026-11-26', 'El servicio pesa menos cuando la verdad no se negocia para ganar comodidad; porque el Señor no solo salva, también forma.', 'Francis Schaeffer');
INSERT INTO daily_reflections (day_of_year, date, quote, author) VALUES (331, '2026-11-27', 'La fe madura cuando la gracia enseña a depender y no a presumir; entonces la teología termina arrodillada en adoración.', 'Martyn Lloyd-Jones');
